mapper.select:
SELECT count(*) AS count FROM comments c LEFT OUTER JOIN users u ON c.USER_EMAIL = u.EMAIL WHERE 1=1
AND (c.content like CONCAT('%', #{word}, '%') OR u.nickname like CONCAT('%', #{word}, '%'))
AND c.DEL_YN = #{delYn}
AND c.post_id = #{postId}
AND c.created_at between STR_TO_DATE(CONCAT(#{today},' 00:00:00'), '%Y-%m-%d %H:%i:%s') and STR_TO_DATE(CONCAT(#{today},' 23:59:59'), '%Y-%m-%d %H:%i:%s')

/*mapper.user.CommentMapper.findComments */ SELECT c.COMMENT_ID AS commentId , c.POST_ID AS postId , c.USER_EMAIL AS userEmail , c.PARENT_COMMENT_ID AS parentCommentId , c.CONTENT AS content , c.CREATED_AT AS createdAt , c.UPDATED_AT AS updatedAt , c.DELETED_AT AS deletedAt , c.DEL_YN AS delYn , u.NICKNAME AS nickname , (SELECT title FROM posts WHERE post_id = c.post_id) AS title , 0 AS likeCount , 0 AS isLiked , (SELECT count(*) FROM reports WHERE TARGET_CODE = '02' AND TARGET_ID = c.COMMENT_ID) AS reportCnt FROM comments c LEFT OUTER JOIN users u ON c.USER_EMAIL = u.EMAIL WHERE 1=1
AND (c.content like CONCAT('%', #{word}, '%') OR u.nickname like CONCAT('%', #{word}, '%'))
AND c.DEL_YN = #{delYn}
AND c.COMMENT_ID < #{lastId}
ORDER BY c.COMMENT_ID DESC LIMIT #{size}
OFFSET #{offset}

